const fs = require('fs/promises');
const path = require('path');
const pdfParse = require('pdf-parse');
const { createWorker } = require('tesseract.js');

const DOCS_DIR = '/app/documents';
const INVOICES_DIR = '/app/invoices';
const OTHER_DIR = '/app/other';
const SUMMARY_PATH = '/app/invoices/summary.csv';

function normalizeText(text) {
  return (text || '').replace(/\r/g, '\n').replace(/\n{2,}/g, '\n');
}

function parseAmountToken(token) {
  if (!token) return null;
  let cleaned = token.replace(/[^0-9.,-]/g, '');
  if (!cleaned) return null;

  // Handle European and US formats heuristically.
  if (cleaned.includes(',') && cleaned.includes('.')) {
    if (cleaned.lastIndexOf(',') > cleaned.lastIndexOf('.')) {
      cleaned = cleaned.replace(/\./g, '').replace(',', '.');
    } else {
      cleaned = cleaned.replace(/,/g, '');
    }
  } else if (cleaned.includes(',')) {
    const parts = cleaned.split(',');
    if (parts.length > 1 && parts[parts.length - 1].length === 2) {
      cleaned = cleaned.replace(/\./g, '').replace(',', '.');
    } else {
      cleaned = cleaned.replace(/,/g, '');
    }
  }

  const val = Number.parseFloat(cleaned);
  return Number.isFinite(val) ? val : null;
}

function lastAmountInLine(line) {
  const matches = line.match(/(?:[$€£]|USD|EUR|GBP|AUD|CAD|INR|JPY|SGD|HKD)?\s*-?\d{1,3}(?:[.,]\d{3})*(?:[.,]\d{2})|(?:[$€£]|USD|EUR|GBP|AUD|CAD|INR|JPY|SGD|HKD)?\s*-?\d+(?:[.,]\d{2})/gi);
  if (!matches || matches.length === 0) return null;
  for (let i = matches.length - 1; i >= 0; i -= 1) {
    const amt = parseAmountToken(matches[i]);
    if (amt !== null) return amt;
  }
  return null;
}

function extractInvoiceAmounts(text) {
  const lines = normalizeText(text)
    .split('\n')
    .map((l) => l.trim())
    .filter(Boolean);

  const totalCandidates = [];
  const amountDueCandidates = [];
  const grandTotalCandidates = [];
  const vatCandidates = [];

  for (const line of lines) {
    const lower = line.toLowerCase();
    const amt = lastAmountInLine(line);
    if (amt === null) continue;

    if (/\b(grand\s*total)\b/.test(lower)) {
      grandTotalCandidates.push(amt);
    }

    if (/\bamount\s*due\b/.test(lower)) {
      amountDueCandidates.push(amt);
    }

    if (/\btotal\b/.test(lower) && !/\bsubtotal\b/.test(lower) && !/\btotal\s*tax\b/.test(lower) && !/\bvat\s*total\b/.test(lower)) {
      totalCandidates.push(amt);
    }

    if (/\b(vat|tax|gst)\b/.test(lower) && !/\b(total|amount\s*due|grand\s*total)\b/.test(lower)) {
      vatCandidates.push(amt);
    }
  }

  // Prefer explicit TOTAL over AMOUNT DUE per requirement.
  let totalAmount = null;
  if (totalCandidates.length > 0) {
    totalAmount = totalCandidates[totalCandidates.length - 1];
  } else if (grandTotalCandidates.length > 0) {
    totalAmount = grandTotalCandidates[grandTotalCandidates.length - 1];
  } else if (amountDueCandidates.length > 0) {
    totalAmount = amountDueCandidates[amountDueCandidates.length - 1];
  }

  const vatAmount = vatCandidates.length > 0 ? vatCandidates[vatCandidates.length - 1] : 0;

  return {
    totalAmount,
    vatAmount,
  };
}

function classifyDocument(text) {
  const lower = (text || '').toLowerCase();
  const strong = [
    /\binvoice\b/,
    /\binvoice\s*(no|number|#)\b/,
    /\bbill\s*to\b/,
    /\bamount\s*due\b/,
    /\bgrand\s*total\b/,
    /\bdue\s*date\b/,
    /\bvat\b/,
    /\bgst\b/,
  ];

  let score = 0;
  for (const re of strong) {
    if (re.test(lower)) score += 1;
  }

  if (/\breceipt\b/.test(lower) && !/\binvoice\b/.test(lower)) score -= 1;
  if (/\bresume\b|\bcurriculum\s*vitae\b|\breport\b|\bcertificate\b/.test(lower)) score -= 2;

  return score >= 2 ? 'invoice' : 'other';
}

async function extractTextFromPdf(filePath) {
  const data = await fs.readFile(filePath);
  const parsed = await pdfParse(data);
  return parsed.text || '';
}

async function extractTextFromImage(filePath, worker) {
  const out = await worker.recognize(filePath);
  return (out?.data?.text) || '';
}

function fmtAmount(n) {
  if (n === null || n === undefined || Number.isNaN(n)) return '';
  return n.toFixed(2);
}

function csvEscape(s) {
  const str = String(s ?? '');
  if (/[",\n]/.test(str)) {
    return `"${str.replace(/"/g, '""')}"`;
  }
  return str;
}

async function main() {
  await fs.mkdir(INVOICES_DIR, { recursive: true });
  await fs.mkdir(OTHER_DIR, { recursive: true });

  const entries = await fs.readdir(DOCS_DIR);
  const files = entries
    .filter((f) => /\.(pdf|jpe?g)$/i.test(f))
    .sort((a, b) => a.localeCompare(b));

  const worker = await createWorker('eng');

  const invoiceRows = [];
  const report = [];

  try {
    for (const filename of files) {
      const src = path.join(DOCS_DIR, filename);
      const ext = path.extname(filename).toLowerCase();

      let text = '';
      try {
        if (ext === '.pdf') {
          text = await extractTextFromPdf(src);
        } else {
          text = await extractTextFromImage(src, worker);
        }
      } catch (err) {
        text = '';
      }

      const cls = classifyDocument(text);
      if (cls === 'invoice') {
        const { totalAmount, vatAmount } = extractInvoiceAmounts(text);
        invoiceRows.push({
          filename,
          total_amount: totalAmount ?? 0,
          vat_amount: vatAmount ?? 0,
        });
        report.push(`${filename} => invoice | total=${fmtAmount(totalAmount ?? 0)} vat=${fmtAmount(vatAmount ?? 0)}`);
      } else {
        report.push(`${filename} => other`);
      }

      const destDir = cls === 'invoice' ? INVOICES_DIR : OTHER_DIR;
      const dest = path.join(destDir, filename);
      await fs.rename(src, dest);
    }
  } finally {
    await worker.terminate();
  }

  const totals = invoiceRows.reduce(
    (acc, row) => {
      acc.total_amount += Number(row.total_amount) || 0;
      acc.vat_amount += Number(row.vat_amount) || 0;
      return acc;
    },
    { total_amount: 0, vat_amount: 0 }
  );

  const lines = ['filename,total_amount,vat_amount'];
  for (const row of invoiceRows) {
    lines.push([
      csvEscape(row.filename),
      csvEscape(fmtAmount(Number(row.total_amount) || 0)),
      csvEscape(fmtAmount(Number(row.vat_amount) || 0)),
    ].join(','));
  }
  lines.push([
    'total',
    fmtAmount(totals.total_amount),
    fmtAmount(totals.vat_amount),
  ].join(','));

  await fs.writeFile(SUMMARY_PATH, `${lines.join('\n')}\n`, 'utf8');

  // Ensure documents directory is empty of files.
  const remaining = await fs.readdir(DOCS_DIR);
  if (remaining.length > 0) {
    throw new Error(`Expected /app/documents to be empty, found: ${remaining.join(', ')}`);
  }

  console.log(report.join('\n'));
  console.log('\nSummary written:', SUMMARY_PATH);
}

main().catch((err) => {
  console.error(err);
  process.exit(1);
});
